(function(){"use strict";let currentPage="home";function render(){const app=document.getElementById("root");app.innerHTML=`<div class="app">${renderHeader()}<main class="main">${renderPage()}</main>${renderFooter()}</div>`;bindEvents()}function renderHeader(){return`<header class="header"><nav class="nav"><div class="logo" data-nav="home">\u{1F680} Power Pages Site</div><ul class="nav-links"><li><a data-nav="home" class="${currentPage==="home"?"active":""}">ホーム</a></li><li><a data-nav="about" class="${currentPage==="about"?"active":""}">概要</a></li></ul></nav></header>`}function renderPage(){if(currentPage==="about")return renderAbout();return renderHome()}function renderHome(){return`<div class="page"><section class="hero"><h1>サイトは現在準備中です</h1><p>このサイトは現在開発中です。まもなく公開されます。</p><div class="status-card"><div class="status-icon">\u2699\uFE0F</div><p>デプロイ済み・コンテンツ更新待ち</p></div></section></div>`}function renderAbout(){return`<div class="page"><h2>概要</h2><p>このポータルは Power Pages でホスティングされています。</p><ul><li>React SPA（本番デプロイ時に置換）</li><li>Dataverse 連携予定</li><li>レスポンシブデザイン</li></ul></div>`}function renderFooter(){return`<footer class="footer"><p>&copy; ${new Date().getFullYear()} Power Pages Site</p></footer>`}function bindEvents(){document.querySelectorAll("[data-nav]").forEach(el=>{el.addEventListener("click",()=>{currentPage=el.dataset.nav;render()})})}document.addEventListener("DOMContentLoaded",render)})();
